    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xF896283F9DD57953ULL + 0xF078DBB1AAA5D316ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0x9ED5FFEAAA53A523ULL + 0x9D0EF3A176A3AF5FULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseA(pNonce * 0x9C437BFD4C9FA975ULL + 0x857863F9010245AEULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0xE5EB8D900AF202EBULL + 0xE312ED22779F9D2AULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseC(pNonce * 0x9EC619BC28A3059BULL + 0xD5745307302A9D0BULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseC(pNonce * 0xC21C46FDB79E0C49ULL + 0xD3F786DB572E3F1AULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0xB49268F347AEE00BULL + 0xDA7AE720803097D7ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseC(pNonce * 0xA7F294422ED9FF2BULL + 0x8DE15ABC445B7279ULL);
