            aOrbiterH = ((aOrbiterH + aOrbiterJ) + 7058958653571907008U) + aNonceWordC;
            aOrbiterD = (aOrbiterD ^ aOrbiterH) ^ 13449110740794915826U;
            aOrbiterD = RotL64((aOrbiterD * 5553795988117678529U), 29U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterB) + 13888910980938271356U;
            aOrbiterC = (aOrbiterC ^ aOrbiterF) ^ 2296568944491534603U;
            aOrbiterC = RotL64((aOrbiterC * 4872327757082025941U), 43U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterG) + 13012890463246556769U;
            aOrbiterH = (aOrbiterH ^ aOrbiterE) ^ 2216292933347597763U;
            aOrbiterH = RotL64((aOrbiterH * 4769826702938045005U), 53U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterE) + 642155129476189238U;
            aOrbiterB = (aOrbiterB ^ aOrbiterA) ^ 3503630502547542525U;
            aOrbiterB = RotL64((aOrbiterB * 11723395497407031165U), 19U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterD) + 3511638179546642583U;
            aOrbiterE = ((aOrbiterE ^ aOrbiterI) ^ 13709728648766598811U) ^ aNonceWordP;
            aOrbiterE = RotL64((aOrbiterE * 12728440373070066533U), 41U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterA) + 13633605383605804849U) + aOrbiterUpdateSaltA[((aIndex + 27U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterK) ^ 13147170576803304873U;
            aOrbiterF = RotL64((aOrbiterF * 14492882767827361851U), 11U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterI) + 6961341036720213086U) + aNonceWordL;
            aOrbiterA = (aOrbiterA ^ aOrbiterC) ^ 7608459893234422574U;
            aOrbiterA = RotL64((aOrbiterA * 9568274058184936409U), 23U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterK) + 7219409098468814641U) + aNonceWordK;
            aOrbiterG = ((aOrbiterG ^ aOrbiterD) ^ 12839616196814066302U) ^ aOrbiterUpdateSaltB[((aIndex + 7U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 192004312641133367U), 21U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterH) + 10779505359766549539U) + aOrbiterUpdateSaltE[(((31U - aIndex) + 18U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterB) ^ 8013037942081799931U;
            aOrbiterI = RotL64((aOrbiterI * 17805842296638049863U), 5U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterF) + 11746068320268791648U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 7344046561384324512U;
