            //
            aIngress = RotL64(aOrbiterB, 23U) ^ aOrbiterJ;
            aIngress = aIngress + (aOrbiterA ^ RotL64(aOrbiterE, 48U));
            aIngress = aIngress + (RotL64(aOrbiterF, 57U) ^ aOrbiterC);
            aIngress = aIngress + (RotL64(aOrbiterG, 11U) ^ aOrbiterH);
            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterD, 21U));
            aIngress = aIngress + RotL64(aOrbiterK, 5U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererE = aWandererE + (((RotL64(aIngress, 27U) + aOrbiterG) + RotL64(aOrbiterF, 11U)) + aNonceWordH);
            aWandererH = aWandererH ^ ((RotL64(aCross, 34U) + aOrbiterK) + RotL64(aOrbiterI, 41U));
            aWandererG = aWandererG + (((RotL64(aPrevious, 39U) + RotL64(aOrbiterI, 35U)) + aOrbiterC) + RotL64(aCarry, 41U));
