            //
            aOrbiterA = (aOrbiterA + aOrbiterI) + 13000323316101441129U;
            aOrbiterH = ((aOrbiterH ^ aOrbiterA) ^ 18041268115707284284U) ^ aOrbiterUpdateSaltB[((aIndex + 5U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 3794337413209498843U), 41U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterK) + 8369334649956676898U;
            aOrbiterG = (aOrbiterG ^ aOrbiterE) ^ 5785356806656900476U;
            aOrbiterG = RotL64((aOrbiterG * 5812498340773342563U), 27U);
            //
